export interface HandoffTicketChannel<T> {
    readonly promise: Promise<T>;
    readonly done: boolean;
    /**
     * `true` when the ticket was created successfully on the server. `false` if
     * ticket creation failed — in that case the promise never resolves on its
     * own, and callers should treat this channel as unavailable and rely on
     * other paths (loopback, paste, etc.).
     */
    readonly available: boolean;
    /** Error from the failed create attempt, when `available` is `false`. */
    readonly startError: Error | null;
    /** Ticket ID for the browser to post completion against (via `?ticket=`). */
    readonly ticketId: string | null;
    reject(err: Error): void;
    close(): void;
}
/**
 * Parallel abstraction to `startLoopbackServer`: a single self-contained
 * delivery path that uses a server-polled handoff ticket with PKCE instead
 * of a local HTTP callback. Works in environments where the browser can't
 * reach the CLI's loopback (SSH, Docker, WSL, cloud IDEs, sandboxes) because
 * the hand-off goes browser → server → CLI poll.
 *
 * Creates the ticket, kicks off polling in the background, and exposes the
 * resulting promise. The caller races this against the loopback server's
 * promise — typically via `runBrowserHandoff` in `browserHandoff.ts`.
 *
 * The generic `T` matches the shape of the ticket's `data` payload as
 * validated by the server (see `handoffTicket.ts` domain `dataSchema`). For
 * example, `auth.login` tickets hydrate to `{ token: string }`;
 * `dataset.start` tickets pass through `{ status, isFetch, ... }`.
 */
export declare function startHandoffTicketChannel<T>(opts: {
    serviceUrl: string;
    kind: string;
    timeoutMs: number;
    ttlSeconds?: number;
    bearer?: string;
}): Promise<HandoffTicketChannel<T>>;
